import React, { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { useInView } from "react-intersection-observer";
import Confetti from "react-confetti";
import axios from "axios";

const RSVPSection = () => {
  const { ref, inView } = useInView({ threshold: 0.2, triggerOnce: true });
  const [form, setForm] = useState({ name: "", email: "", attending: "yes", guests: "1", message: "" });
  const [status, setStatus] = useState("idle"); // idle | loading | success | error
  const [showConfetti, setShowConfetti] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setStatus("loading");
    try {
      await axios.post("http://localhost:5000/rsvp", form);
      setStatus("success");
      setShowConfetti(true);
      setTimeout(() => setShowConfetti(false), 6000);
    } catch {
      setStatus("error");
    }
  };

  const inputClass =
    "w-full bg-white/5 border border-gold/20 rounded px-4 py-3 text-beige font-body text-sm placeholder-beige/30 focus:border-gold transition-all duration-300";

  return (
    <section
      ref={ref}
      id="rsvp"
      className="relative py-24 px-4 overflow-hidden"
      style={{ background: "linear-gradient(180deg, #1a0a0a 0%, #0d0000 100%)" }}
    >
      {showConfetti && (
        <Confetti
          numberOfPieces={300}
          colors={["#D4AF37", "#F5D76E", "#8B0000", "#ffffff", "#B8860B"]}
          recycle={false}
        />
      )}

      <motion.div
        initial={{ opacity: 0, y: 40 }}
        animate={inView ? { opacity: 1, y: 0 } : {}}
        transition={{ duration: 1 }}
        className="text-center mb-16"
      >
        <span className="ornament">✦ ✦ ✦</span>
        <h2 className="font-serif text-4xl md:text-5xl gold-text mt-4 mb-2">RSVP</h2>
        <p className="font-sans text-beige/50 tracking-widest text-sm uppercase">
          Kindly respond by {new Date(Date.now() + 14 * 24 * 60 * 60 * 1000).toLocaleDateString("en-IN", { day: "numeric", month: "long", year: "numeric" })}
        </p>
      </motion.div>

      <div className="max-w-lg mx-auto">
        <AnimatePresence mode="wait">
          {status === "success" ? (
            <motion.div
              key="success"
              initial={{ opacity: 0, scale: 0.8 }}
              animate={{ opacity: 1, scale: 1 }}
              exit={{ opacity: 0 }}
              className="glass-card rounded-lg p-12 text-center"
            >
              <motion.div
                animate={{ scale: [1, 1.2, 1], rotate: [0, 10, -10, 0] }}
                transition={{ duration: 0.6 }}
                className="text-6xl mb-6"
              >
                🎉
              </motion.div>
              <h3 className="font-serif text-3xl gold-text mb-4">Thank You!</h3>
              <p className="font-body text-beige/70 leading-relaxed">
                Your RSVP has been received. We can't wait to celebrate with you!
              </p>
              <div className="section-divider my-6" />
              <p className="font-serif italic text-gold/60 text-sm">
                — With love, Arjun & Priya —
              </p>
            </motion.div>
          ) : (
            <motion.form
              key="form"
              initial={{ opacity: 0, y: 40 }}
              animate={inView ? { opacity: 1, y: 0 } : {}}
              transition={{ duration: 0.8, delay: 0.2 }}
              onSubmit={handleSubmit}
              className="glass-card rounded-lg p-8 space-y-5"
            >
              <div>
                <label className="block text-gold/70 text-xs tracking-widest uppercase mb-2 font-body">
                  Full Name *
                </label>
                <input
                  type="text"
                  name="name"
                  required
                  value={form.name}
                  onChange={handleChange}
                  placeholder="Your full name"
                  className={inputClass}
                />
              </div>

              <div>
                <label className="block text-gold/70 text-xs tracking-widest uppercase mb-2 font-body">
                  Email Address *
                </label>
                <input
                  type="email"
                  name="email"
                  required
                  value={form.email}
                  onChange={handleChange}
                  placeholder="your@email.com"
                  className={inputClass}
                />
              </div>

              <div>
                <label className="block text-gold/70 text-xs tracking-widest uppercase mb-2 font-body">
                  Will you attend? *
                </label>
                <div className="grid grid-cols-2 gap-3">
                  {["yes", "no"].map((opt) => (
                    <label
                      key={opt}
                      className={`flex items-center justify-center gap-2 p-3 rounded border cursor-pointer transition-all duration-300 font-body text-sm ${
                        form.attending === opt
                          ? "border-gold bg-gold/10 text-gold"
                          : "border-gold/20 text-beige/50 hover:border-gold/40"
                      }`}
                    >
                      <input
                        type="radio"
                        name="attending"
                        value={opt}
                        checked={form.attending === opt}
                        onChange={handleChange}
                        className="hidden"
                      />
                      {opt === "yes" ? "✓ Joyfully Accept" : "✗ Regretfully Decline"}
                    </label>
                  ))}
                </div>
              </div>

              {form.attending === "yes" && (
                <motion.div
                  initial={{ opacity: 0, height: 0 }}
                  animate={{ opacity: 1, height: "auto" }}
                  exit={{ opacity: 0, height: 0 }}
                >
                  <label className="block text-gold/70 text-xs tracking-widest uppercase mb-2 font-body">
                    Number of Guests
                  </label>
                  <select name="guests" value={form.guests} onChange={handleChange} className={inputClass}>
                    {[1, 2, 3, 4, 5].map((n) => (
                      <option key={n} value={n} className="bg-dark-bg">
                        {n} {n === 1 ? "Guest" : "Guests"}
                      </option>
                    ))}
                  </select>
                </motion.div>
              )}

              <div>
                <label className="block text-gold/70 text-xs tracking-widest uppercase mb-2 font-body">
                  Message (Optional)
                </label>
                <textarea
                  name="message"
                  value={form.message}
                  onChange={handleChange}
                  placeholder="Share your wishes..."
                  rows={3}
                  className={inputClass}
                />
              </div>

              {status === "error" && (
                <p className="text-red-400 text-sm text-center font-body">
                  Something went wrong. Please try again.
                </p>
              )}

              <motion.button
                type="submit"
                disabled={status === "loading"}
                className="btn-gold w-full rounded flex items-center justify-center gap-2"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
              >
                {status === "loading" ? (
                  <>
                    <motion.span
                      animate={{ rotate: 360 }}
                      transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
                    >
                      ⟳
                    </motion.span>
                    Sending...
                  </>
                ) : (
                  "Send RSVP 💌"
                )}
              </motion.button>
            </motion.form>
          )}
        </AnimatePresence>
      </div>
    </section>
  );
};

export default RSVPSection;
